DeltaPDR1=pdr1_s1(:,:,3,1,1)./pdr1_s1(:,:,1,1,1)-1;
DeltaPDR2=pdr2_s1(:,:,3,1,1)./pdr2_s1(:,:,1,1,1)-1;
