DeltaP2=pdr2_s1(:,:,3,1,1).*div2_s1(:,:,3,1,1)./(pdr2_s1(:,:,1,1,1).*div2_s1(:,:,1,1,1))-1;
DeltaD1=div1_s1(:,:,3,1,1)./div1_s1(:,:,1,1,1)-1;
DeltaD2=div2_s1(:,:,3,1,1)./div2_s1(:,:,1,1,1)-1;
DeltaRf=rf_s1(:,:,3,1,1)-rf_s1(:,:,1,1,1);
DeltaCP=ep2_s1(:,:,3,1,1)-ep1_s1(:,:,3,1,1)-(ep2_s1(:,:,1,1,1)-ep1_s1(:,:,1,1,1));

%% Code für Simulation
%time.number=(time.max-time.min)/time.delta;
time.number=(2101-time.min)/time.delta;
disp([datestr(now), ': Start Simulation of the World Economy']);
error=0;
calib.phi=2.6;
simulation.number=1000;
