[simulation.mac,simulation.neg, simulation.d, simulation.nu, simulation.Cumulative_Emissions, simulation.Emissions, simulation.Y1, simulation.Y2,simulation.E1, simulation.E2, simulation.D1, simulation.D2, simulation.C, simulation.Output, simulation.T, simulation.Tmod, simulation.K1, simulation.K2, simulation.S, simulation.X, simulation.Y, simulation.B]=deal(NaN(simulation.number, time.number+1));
[simulation.tax,simulation.i1,simulation.i2,simulation.g1,simulation.g2,simulation.f1,simulation.f2,simulation.chi,simulation.r]=deal(NaN(simulation.number, time.number+1));
[simulation.pi_energy, simulation.pi, simulation.q1, simulation.q2, simulation.rf, simulation.ep1, simulation.ep2, simulation.cp, simulation.pdr1, simulation.pdr2]=deal(NaN(simulation.number, time.number+1));
[simulation.D1mu, simulation.D2mu,simulation.D1sigma1, simulation.D2sigma1,simulation.D1sigma2,simulation.D2sigma2,simulation.D1sigma3,simulation.D2sigma3,simulation.D1trans, simulation.D2trans, simulation.div1, simulation.div2, simulation.jumps, simulation.jump_c, simulation.g, simulation.C_Y, simulation.Cg, simulation.Cf, simulation.Ctot, simulation.Cratio]=deal(NaN(simulation.number, time.number+1));

