temp_index_temperature     = find(simulation.T(1,1)-temperature.vector <0 ,1);

temp_dif_state=(simulation.S(1,1)-state.vector(temp_index_state-1))/state.delta;
temp_dif_temperature=(simulation.T(1,1)-temperature.vector(temp_index_temperature-1))/temperature.delta;
if simulation.S(1,1)>=state.max
    temp_index_state= state.number+1;
    temp_dif_state=0;
end
