            +(1-temp_dif_state).*(1-temp_dif_temperature).*i1_s1(temp_index_state-1,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*temp_dif_temperature.*i1_s1(temp_index_state-1,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +temp_dif_state.*(1-temp_dif_temperature).*i1_s1(temp_index_state,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1));
        
