            +(1-temp_dif_state).*(1-temp_dif_temperature).*f1_s1(temp_index_state-1,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*temp_dif_temperature.*f1_s1(temp_index_state-1,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +temp_dif_state.*(1-temp_dif_temperature).*f1_s1(temp_index_state,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1));        

simulation.f2(:,1)     = temp_dif_state.*temp_dif_temperature.*f2_s1(temp_index_state,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*(1-temp_dif_temperature).*f2_s1(temp_index_state-1,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*temp_dif_temperature.*f2_s1(temp_index_state-1,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +temp_dif_state.*(1-temp_dif_temperature).*f2_s1(temp_index_state,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1)); 

simulation.g1(:,1)     = temp_dif_state.*temp_dif_temperature.*g1_s1(temp_index_state,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*(1-temp_dif_temperature).*g1_s1(temp_index_state-1,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*temp_dif_temperature.*g1_s1(temp_index_state-1,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +temp_dif_state.*(1-temp_dif_temperature).*g1_s1(temp_index_state,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1));  

simulation.g2(:,1)     = temp_dif_state.*temp_dif_temperature.*g2_s1(temp_index_state,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*(1-temp_dif_temperature).*g2_s1(temp_index_state-1,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +(1-temp_dif_state).*temp_dif_temperature.*g2_s1(temp_index_state-1,temp_index_temperature,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1))...
            +temp_dif_state.*(1-temp_dif_temperature).*g2_s1(temp_index_state,temp_index_temperature-1,simulation.Y(1,1),simulation.X(1,1),simulation.B(1,1)); 
        
